package main

import (
	"fmt"
	"io/ioutil"
	"net/http"
)

func main() {
	// Define the URL to request
	url := "https://api.example.com/data"

	// Create a new HTTP client
	client := &http.Client{}

	// Make a GET request
	resp, err := client.Get(url)
	if err != nil {
		fmt.Println("Error making request:", err)
		return
	}
	defer resp.Body.Close()

	// Check if the request was successful
	if resp.StatusCode != http.StatusOK {
		fmt.Printf("Request failed with status code: %d\n", resp.StatusCode)
		return
	}

	// Read the response body
	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		fmt.Println("Error reading response body:", err)
		return
	}

	// Print the response body
	fmt.Println("Response Body:", string(body))
}
```

### Explanation:
1. **Importing Packages**: We import the necessary packages, including `fmt` for printing, `io/ioutil` for reading the response body, and `net/http` for making the HTTP request.

2. **URL**: The URL you want to request is defined. Replace `"https://api.example.com/data"` with the actual URL you want to access.

3. **HTTP Client**: We create a new HTTP client using `&http.Client{}`.

4. **Make Request**: We use the `client.Get(url)` method to make a GET request to the specified URL. If the request fails, the code prints an error message and exits.

5. **Check Status Code**: We check if the response status code is `http.StatusOK` (200). If not, we print an error message and exit.

6. **Read Response Body**: We read the response body using `ioutil.ReadAll(resp.Body)`. If there is an error reading the body, we print an error message and exit.

7. **Print Response Body**: Finally, we print the response body as a string.

